olve spool tag from tray state\n    spool_tag = _resolve_spool_tag(tray_state)\n\n    # Parse filament usage from G-code\n    filament_used = _parse_gcode_filament_usage(gcode_data)\n\n    # Adjust filament usage for off-by-one bug fix: use -1 instead of -2\n    adjusted_filament_used = filament_used - 1\n\n    # Report usage to Spoolman\n    try:\n        await client.report_usage(spool_tag, adjusted_filament_used)\n        logger.info(f\"Reported {adjusted_filament_used}mm usage for spool {spool_tag} on print {print_id}\")\n    except Exception as e:\n        logger.error(f\"Failed to report usage to Spoolman for print {print_id}: {e}\")\n\n"
